// Extract event data from router payload
const input = $input.first().json;

// Router sends: { event_id, event_type, project_id, payload }
const eventId = input.body?.event_id || input.event_id;
const projectId = input.body?.project_id || input.project_id;
const payload = input.body?.payload || input.payload || {};

// Calculate year folder key
const year = new Date().getFullYear();
const stepKey = `drive_year:${year}`;

return {
  json: {
    event_id: eventId,
    project_id: projectId,
    year: year,
    step_key: stepKey,
    payload: payload
  }
};

// Step already done or in progress by another run
const claimResult = $input.first().json;
const eventData = $('Parse Event Data').first().json;

if (claimResult.current_status === 'DONE') {
  // Already done, we can still emit the next event for THIS project
  return {
    json: {
      action: 'skip_but_emit',
      reason: 'Year folder already exists',
      year_folder_id: claimResult.existing_payload?.folder_id || null,
      project_id: eventData.project_id,
      event_id: eventData.event_id,
      year: eventData.year
    }
  };
}

// IN_PROGRESS by another run - do nothing
return {
  json: {
    action: 'exit',
    reason: 'Step in progress by another run',
    current_status: claimResult.current_status
  }
};

// Extract folder ID from search result
const searchResult = $input.first().json;
const folderId = searchResult.files[0].id;

return {
  json: {
    folder_id: folderId,
    folder_name: searchResult.files[0].name,
    source: 'existing'
  }
};

// Extract folder ID from create result
const createResult = $input.first().json;

return {
  json: {
    folder_id: createResult.id,
    folder_name: createResult.name,
    source: 'created'
  }
};

// Prepare event payload
const folderResult = $('Extract Existing ID').first()?.json || $('Extract Created ID').first()?.json;
const eventData = $('Parse Event Data').first().json;

return {
  json: {
    project_id: eventData.project_id,
    event_id: eventData.event_id,
    year: eventData.year,
    year_folder_id: folderResult.folder_id
  }
};

// Also emit event when year folder already existed
const data = $input.first().json;

return {
  json: {
    project_id: data.project_id,
    event_id: data.event_id,
    year: data.year,
    year_folder_id: data.year_folder_id
  }
};

return {
  json: {
    status: 'success',
    message: 'DRIVE_YEAR_READY emitted',
    project_id: $input.first().json.project_id
  }
};

return {
  json: {
    status: 'success',
    message: 'DRIVE_YEAR_READY emitted (reused folder)',
    project_id: $input.first().json.project_id
  }
};

// Exit - another run is handling this
return {
  json: {
    status: 'skipped',
    message: 'Step in progress by another run'
  }
};

